.darma-loader-darma-custom-554 {color: var(--loader-color, #db2777);
   width: 25px;
   aspect-ratio: 1;
   display: grid;
}
.darma-loader-darma-custom-554, .darma-loader-darma-custom-554:before, .darma-loader-darma-custom-554:after  {
  --c:no-repeat linear-gradient(var(--loader-color, #db2777) 0 0);
   background:var(--c), var(--c), var(--c), var(--c);
   animation: darma-loader-darma-custom-554-l20-1 1.5s infinite linear, darma-loader-darma-custom-554-l20-2 1.5s infinite linear;
}
.darma-loader-darma-custom-554:before, .darma-loader-darma-custom-554:after  {
  content: "";
   grid-area: 1/1;
   transform: translate(calc(100% - 4px),calc(4px - 100%)) rotate(90deg);
}
.darma-loader-darma-custom-554:after  {
  transform: translate(calc(4px - 100%),calc(100% - 4px)) rotate(-90deg);
}
@keyframes darma-loader-darma-custom-554-l20-1  {
  0% {background-size: 0 4px,4px 0 ,0 4px,4px 0 }
12.5%{background-size: 100% 4px,4px 0 ,0 4px,4px 0 }
25% {background-size: 100% 4px,4px 100%,0 4px,4px 0 }
37.5%{background-size: 100% 4px,4px 100%,100% 4px,4px 0 }
43%, 57% {background-size: 100% 4px,4px 100%,100% 4px,4px 100%}
62.5%{background-size: 0 4px,4px 100%,100% 4px,4px 100%}
75% {background-size: 0 4px,4px 0 ,100% 4px,4px 100%}
87.5%{background-size: 0 4px,4px 0 ,0 4px,4px 100%}
100% {background-size: 0 4px,4px 0 ,0 4px,4px 0 }
}
@keyframes darma-loader-darma-custom-554-l20-2  {
  0%,49.9%{background-position: 0 0 ,100% 0 ,100% 100%,0 100%}
50%,100%{background-position: 100% 0,100% 100%,0 100%,0 0 }
}

